/**
* @defgroup Constants Constants
* @brief This category contains constants
* @{
*/
#if defined(FPL_PLATFORM_WINDOWS)
#	if defined(MAX_PATH)
#		define FPL__M_MAX_FILENAME_LENGTH (MAX_PATH)
#		define FPL__M_MAX_PATH_LENGTH (MAX_PATH * 2)
#	else
#		define FPL__M_MAX_FILENAME_LENGTH (260)
#		define FPL__M_MAX_PATH_LENGTH (260 * 2)
#	endif
#	define FPL__M_PATH_SEPARATOR '\\'
#	define FPL__M_FILE_EXT_SEPARATOR '.'
#else
#	define FPL__M_MAX_FILENAME_LENGTH (512)
#	define FPL__M_MAX_PATH_LENGTH (2048)
#	define FPL__M_PATH_SEPARATOR '/'
#	define FPL__M_FILE_EXT_SEPARATOR '.'
#endif

/**
* @def FPL_MAX_FILENAME_LENGTH
* @brief Maximum length of a filename.
* @note On Windows this is `MAX_PATH` (260) when `MAX_PATH` is visible at preprocess time, otherwise hard-coded to 260. On POSIX it is 512.
*/
#define FPL_MAX_FILENAME_LENGTH FPL__M_MAX_FILENAME_LENGTH

/**
* @def FPL_MAX_PATH_LENGTH
* @brief Maximum length of a path.
* @note On Windows this is `MAX_PATH * 2` (520) and on POSIX it is 2048. Internal Win32 path buffers are sized by this constant, so paths longer than `MAX_PATH` are not supported on Windows. The Windows long-path prefix `\\?\` is intentionally not used by FPL ‚ÄĒ callers that need long-path support must work around this at the application level.
*/
#define FPL_MAX_PATH_LENGTH FPL__M_MAX_PATH_LENGTH

/**
* @def FPL_PATH_SEPARATOR
* @brief Path separator character.
*/
#define FPL_PATH_SEPARATOR FPL__M_PATH_SEPARATOR

/**
* @def FPL_FILE_EXT_SEPARATOR
* @brief File extension character.
*/
#define FPL_FILE_EXT_SEPARATOR FPL__M_FILE_EXT_SEPARATOR

/**
* @def FPL_MAX_NAME_LENGTH
* @brief Maximum length of a name (in characters).
*/
#define FPL_MAX_NAME_LENGTH (256)

/**
* @def FPL_MAX_BUFFER_LENGTH
* @brief Maximum length of an internal buffer (in bytes).
*/
#define FPL_MAX_BUFFER_LENGTH (2048)

/** @} */

